import { cn } from '@/utils/cn';
import { ZIndex, ZIndexType } from '@components/z-index';
import FlipHorizontal2 from 'lucide-solid/icons/flip-horizontal-2';
import FlipVertical2 from 'lucide-solid/icons/flip-vertical-2';
import Info from 'lucide-solid/icons/info';
import Maximize2 from 'lucide-solid/icons/maximize-2';
import RotateCcw from 'lucide-solid/icons/rotate-ccw';
import RotateCw from 'lucide-solid/icons/rotate-cw';
import X from 'lucide-solid/icons/x';
import ZoomIn from 'lucide-solid/icons/zoom-in';
import ZoomOut from 'lucide-solid/icons/zoom-out';
import { createSignal, mergeProps, onCleanup, onMount, Show } from 'solid-js';

type ImagePreviewClassProps = {
  backdrop?: string;
  close?: string;
  box?: string;
  img?: string;
  toolbar?: string;
  toolBtn?: string;
  zoomLabel?: string;
  infoPopup?: string;
};

export type ImagePreviewProps = {
  src: string;
  imageName?: string;
  size?: string;
  createdAt?: Date | string;
  modifiedAt?: Date | string;
  onClose: () => void;
  closeOnBackdrop?: boolean;
  closeOnEsc?: boolean;
  class?: ImagePreviewClassProps;
  zIndex?: number;
};

const ZOOM_STEP = 0.25;
const ZOOM_MIN = 0.25;
const ZOOM_MAX = 4;

function formatDate(value: Date | string | undefined): string | undefined {
  if (!value) return undefined;
  const d = value instanceof Date ? value : new Date(value);
  if (isNaN(d.getTime())) return String(value);
  return d.toLocaleString('en-US', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
  });
}

function InfoRow(props: { label: string; value: string | undefined }) {
  return (
    <Show when={props.value}>
      <div class="flex items-start gap-2">
        <span class="w-24 shrink-0 text-white/40">{props.label}</span>
        <span class="min-w-0 break-all text-white/90">{props.value}</span>
      </div>
    </Show>
  );
}

export function ImagePreview(p: ImagePreviewProps) {
  p = mergeProps({ closeOnBackdrop: false, closeOnEsc: true }, p);
  const [rotate, setRotate] = createSignal(0);
  const [flipH, setFlipH] = createSignal(false);
  const [flipV, setFlipV] = createSignal(false);
  const [scale, setScale] = createSignal(1);
  const [offsetX, setOffsetX] = createSignal(0);
  const [offsetY, setOffsetY] = createSignal(0);
  const [isDragging, setIsDragging] = createSignal(false);
  const [showInfo, setShowInfo] = createSignal(false);
  const [naturalSize, setNaturalSize] = createSignal<{ w: number; h: number } | null>(null);

  let dragStartX = 0;
  let dragStartY = 0;
  let dragStartOffsetX = 0;
  let dragStartOffsetY = 0;

  const canPan = () => scale() > 1;

  const imgTransform = () => {
    const sx = flipH() ? -scale() : scale();
    const sy = flipV() ? -scale() : scale();
    return `translate(${offsetX()}px, ${offsetY()}px) rotate(${rotate()}deg) scale(${sx}, ${sy})`;
  };

  const zoomIn = () => setScale(s => Math.min(+(s + ZOOM_STEP).toFixed(2), ZOOM_MAX));

  const zoomOut = () => {
    const next = Math.max(+(scale() - ZOOM_STEP).toFixed(2), ZOOM_MIN);
    setScale(next);
    if (next <= 1) {
      setOffsetX(0);
      setOffsetY(0);
    }
  };

  const resetView = () => {
    setScale(1);
    setOffsetX(0);
    setOffsetY(0);
  };

  const rotateCw = () => {
    setRotate(r => r + 90);
    setOffsetX(0);
    setOffsetY(0);
  };
  const rotateCcw = () => {
    setRotate(r => r - 90);
    setOffsetX(0);
    setOffsetY(0);
  };
  const doFlipH = () => setFlipH(v => !v);
  const doFlipV = () => setFlipV(v => !v);

  const onPointerDown = (e: PointerEvent) => {
    if (!canPan()) return;
    e.preventDefault();
    (e.currentTarget as HTMLElement).setPointerCapture(e.pointerId);
    setIsDragging(true);
    dragStartX = e.clientX;
    dragStartY = e.clientY;
    dragStartOffsetX = offsetX();
    dragStartOffsetY = offsetY();
  };

  const onPointerMove = (e: PointerEvent) => {
    if (!isDragging()) return;
    setOffsetX(dragStartOffsetX + e.clientX - dragStartX);
    setOffsetY(dragStartOffsetY + e.clientY - dragStartY);
  };

  const onPointerUp = () => setIsDragging(false);

  let backdropRef!: HTMLDivElement;
  let boxRef!: HTMLDivElement;
  let infoPopupRef!: HTMLDivElement;
  let infoBtnRef!: HTMLButtonElement;

  onMount(() => {
    const onWheel = (e: WheelEvent) => {
      e.preventDefault();
      const delta = e.deltaY < 0 ? ZOOM_STEP : -ZOOM_STEP;
      const oldScale = scale();
      const newScale = Math.min(Math.max(+(oldScale + delta).toFixed(2), ZOOM_MIN), ZOOM_MAX);
      if (newScale === oldScale) return;

      const rect = boxRef.getBoundingClientRect();
      const cx = e.clientX - rect.left - rect.width / 2;
      const cy = e.clientY - rect.top - rect.height / 2;
      const ratio = newScale / oldScale - 1;

      setScale(newScale);
      setOffsetX(ox => ox - (cx - ox) * ratio);
      setOffsetY(oy => oy - (cy - oy) * ratio);

      if (newScale <= 1) {
        setOffsetX(0);
        setOffsetY(0);
      }
    };

    const onKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape' && (p.closeOnEsc ?? true)) {
        e.stopImmediatePropagation();
        p.onClose();
      }
    };

    const onDocPointerDown = (e: PointerEvent) => {
      if (!showInfo()) return;
      const target = e.target as Node;
      if (!infoPopupRef?.contains(target) && !infoBtnRef?.contains(target)) {
        setShowInfo(false);
      }
    };

    const preventScroll = (e: WheelEvent) => e.preventDefault();
    backdropRef.addEventListener('wheel', preventScroll, { passive: false });
    boxRef.addEventListener('wheel', onWheel, { passive: false });
    document.addEventListener('pointerdown', onDocPointerDown);
    document.addEventListener('keydown', onKeyDown, { capture: true });

    onCleanup(function removePreviewEventListeners() {
      backdropRef.removeEventListener('wheel', preventScroll);
      boxRef.removeEventListener('wheel', onWheel);
      document.removeEventListener('pointerdown', onDocPointerDown);
      document.removeEventListener('keydown', onKeyDown, { capture: true });
    });
  });

  const hasInfo = () => !!(p.imageName || p.size || p.createdAt || p.modifiedAt);

  return (
    <ZIndex
      open={true}
      type={ZIndexType.MODAL}
      blockScroll={true}
      positioning="fixed"
      preRender={false}
      customValue={p.zIndex}
      class="inset-0"
    >
      <div
        ref={backdropRef}
        class={cn('img01', p.class?.backdrop)}
        onClick={p.closeOnBackdrop ? p.onClose : undefined}
      >
        <button class={cn('img02', p.class?.close)} onClick={p.onClose}>
          <X size={20} />
        </button>

        <div
          ref={boxRef}
          class={cn(
            'img03',
            canPan() && (isDragging() ? 'cursor-grabbing' : 'cursor-grab'),
            p.class?.box,
          )}
          onClick={e => e.stopPropagation()}
          onPointerDown={onPointerDown}
          onPointerMove={onPointerMove}
          onPointerUp={onPointerUp}
          onPointerCancel={onPointerUp}
        >
          <img
            src={p.src}
            alt={p.imageName}
            class={cn('img04', isDragging() && 'img04--drag', p.class?.img)}
            style={{ transform: imgTransform() }}
            draggable={false}
            onLoad={e => {
              const img = e.currentTarget as HTMLImageElement;
              setNaturalSize({ w: img.naturalWidth, h: img.naturalHeight });
            }}
          />
        </div>

        <div class={cn('img05', p.class?.toolbar)} onClick={e => e.stopPropagation()}>
          <button class={cn('img06', p.class?.toolBtn)} onClick={doFlipV} title="Flip vertically">
            <FlipVertical2 size={16} />
          </button>
          <button class={cn('img06', p.class?.toolBtn)} onClick={doFlipH} title="Flip horizontally">
            <FlipHorizontal2 size={16} />
          </button>
          <div class="img07" />
          <button
            class={cn('img06', p.class?.toolBtn)}
            onClick={rotateCcw}
            title="Rotate counter-clockwise"
          >
            <RotateCcw size={16} />
          </button>
          <button class={cn('img06', p.class?.toolBtn)} onClick={rotateCw} title="Rotate clockwise">
            <RotateCw size={16} />
          </button>
          <div class="img07" />
          <button
            class={cn('img06', p.class?.toolBtn)}
            onClick={zoomOut}
            title="Zoom out"
            disabled={scale() <= ZOOM_MIN}
          >
            <ZoomOut size={16} />
          </button>
          <span class={cn('img08', p.class?.zoomLabel)}>{Math.round(scale() * 100)}%</span>
          <button
            class={cn('img06', p.class?.toolBtn)}
            onClick={zoomIn}
            title="Zoom in"
            disabled={scale() >= ZOOM_MAX}
          >
            <ZoomIn size={16} />
          </button>
          <div class="img07" />
          <button
            class={cn('img06', p.class?.toolBtn)}
            onClick={resetView}
            title="Reset to 100%"
            disabled={scale() === 1}
          >
            <Maximize2 size={16} />
          </button>

          <Show when={hasInfo()}>
            <div class="img07" />
            <div class="relative">
              <button
                ref={infoBtnRef}
                class={cn('img06', showInfo() && 'bg-white/20 text-white', p.class?.toolBtn)}
                onClick={() => setShowInfo(v => !v)}
                title="Image info"
              >
                <Info size={16} />
              </button>

              <Show when={showInfo()}>
                <div ref={infoPopupRef} class={cn('img09', p.class?.infoPopup)}>
                  <p class="mb-2 text-xs font-semibold tracking-wide text-white/50 uppercase">
                    Image Info
                  </p>
                  <div class="flex flex-col gap-1.5 text-xs">
                    <InfoRow label="File name" value={p.imageName} />
                    <InfoRow label="Size" value={p.size} />
                    <InfoRow
                      label="Dimension"
                      value={
                        naturalSize() ? `${naturalSize()!.w} × ${naturalSize()!.h} px` : undefined
                      }
                    />
                    <InfoRow label="Created" value={formatDate(p.createdAt)} />
                    <InfoRow label="Modified" value={formatDate(p.modifiedAt)} />
                  </div>
                </div>
              </Show>
            </div>
          </Show>
        </div>
      </div>
    </ZIndex>
  );
}
